class Solution {
public:
    bool solve(vector<vector<char>>& maze, int n, int m, int x, int y, int x2, int y2, vector<pair<int,int>> visited) {
        for (int dx = 1; dx >= -1; dx--) {
            for (int dy = 1; dy >= -1; dy--) {
                int nx = x + dx, ny = y + dy;
                if (nx < 0 || nx >= n || ny < 0 || ny >= m || maze[nx][ny] == \#) continue;
                if ((nx, ny) == make_pair(x2, y2)) return true;
                visited.push_back(make_pair(nx, ny));
            }
        } return false;
    }
};
int main() {
    int n, m, x, y, x2, y2;
    cin >> n >> m >> x >> y >> x2 >> y2;
    vector<vector<char>> maze(n, vector<char>(m));
    for (int i=0;i<n;i++) for (int j=0;j<m;j++) cin >> maze[i][j];
    Solution sol;
    vector<pair<int,int>> visited;
    cout<<(sol.solve(maze, n, m, x, y, x2, y2, visited) ? "true" : "false") << endl;
    return 0;
}
